proof_block:
// The ensures is structurally `BIG ==> det_equal`, where BIG is the four-conjunct
// block. In the previous attempt we asserted the conjuncts as if they were
// hypotheses — but BIG is the *antecedent* of an implication, not part of the
// proof context, so `assert(in_dom == r1.is_Some())` was unprovable.
//
// The correct shape is `assert(BIG ==> det_equal) by { ... }`: inside the `by`
// block we may assume BIG and then prove det_equal. We mirror the ensures
// antecedent verbatim (using `r1.is_Some()` / `r2.is_Some()` to match) and let
// the `if m.dom().contains(va)` case-split handle the Some/None dichotomy.

let pt = self_.get_pagetable_by_pcid(pcid).unwrap();
let m = pt.mapping_4k();

assert(({
    &&& (m.dom().contains(va) == r1.is_Some())
    &&& (r1.is_Some() ==> m.dom().contains(va) && m[va] == page_entry_to_map_entry(&r1.unwrap()))
    &&& (m.dom().contains(va) == r2.is_Some())
    &&& (r2.is_Some() ==> m.dom().contains(va) && m[va] == page_entry_to_map_entry(&r2.unwrap()))
}) ==> det_resolve_pagetable_mapping_equal(r1, r2)) by {
    // Inside this `by`-block the four conjuncts are available as hypotheses.
    if m.dom().contains(va) {
        // From conjuncts (1) and (3): both options are Some.
        assert(r1.is_Some());
        assert(r2.is_Some());
        let e1 = r1.unwrap();
        let e2 = r2.unwrap();

        // From conjuncts (2) and (4): both runs pin m[va] to the same MapEntry.
        assert(m[va] == page_entry_to_map_entry(&e1));
        assert(m[va] == page_entry_to_map_entry(&e2));
        assert(page_entry_to_map_entry(&e1) == page_entry_to_map_entry(&e2));

        // `page_entry_to_map_entry` is `when_used_as_spec(spec_page_entry_to_map_entry)`,
        // and `spec_page_entry_to_map_entry` is `pub open spec fn` returning
        // `MapEntry { addr: p.addr, write: p.perm.write, execute_disable: p.perm.execute_disable }`,
        // so the equality unfolds to field-wise equality on the three MapEntry fields.
        assert(page_entry_to_map_entry(&e1)
            == MapEntry { addr: e1.addr, write: e1.perm.write, execute_disable: e1.perm.execute_disable });
        assert(page_entry_to_map_entry(&e2)
            == MapEntry { addr: e2.addr, write: e2.perm.write, execute_disable: e2.perm.execute_disable });
        assert(e1.addr == e2.addr);
        assert(e1.perm.write == e2.perm.write);
        assert(e1.perm.execute_disable == e2.perm.execute_disable);

        // `View for PageEntry` is defined in the same module as
        // `det_resolve_pagetable_mapping`, so the `closed spec fn view` body
        // `PageEntryView { addr: self.addr, perm: self.perm }` is visible here
        // and lifts to view-equality via the field equalities above.
        assert(e1.view() == PageEntryView { addr: e1.addr, perm: e1.perm });
        assert(e2.view() == PageEntryView { addr: e2.addr, perm: e2.perm });
        assert(e1.view() =~= e2.view());
        assert(e1.view() == e2.view());

        // The det predicate now closes from `(r1 is Some) == (r2 is Some)` and
        // the view equality just established.
        assert(det_resolve_pagetable_mapping_equal(r1, r2));
    } else {
        // From conjuncts (1) and (3): both r1 and r2 are None — det is vacuous.
        assert(!r1.is_Some());
        assert(!r2.is_Some());
        assert((r1 is Some) == (r2 is Some));
        assert(det_resolve_pagetable_mapping_equal(r1, r2));
    }
};
